 12→// --- Tests for gen-make ---
 13→
 14→func TestRunGenMake_MissingTasksFlag(t *testing.T) {
 15→	err := runGenMake([]string{"--out", "out.mk"})
 16→	if err == nil {
 17→		t.Fatal("expected error for missing --tasks")
 18→	}
