 79→func TestRunGenMake_SingleTask(t *testing.T) {
 80→	tmp := t.TempDir()
 81→	tasksPath := filepath.Join(tmp, "tasks.yaml")
 82→	outPath := filepath.Join(tmp, "targets.mk")
 83→
 84→	yaml := `- id: build-widget
 85→  prompt: .kiln/prompts/tasks/build-widget.md
 86→  needs: []
 87→`
 88→	os.WriteFile(tasksPath, []byte(yaml), 0o644)
 89→
 90→	err := runGenMake([]string{"--tasks", tasksPath, "--out", outPath})
 91→	if err != nil {
 92→		t.Fatalf("unexpected error: %v", err)
 93→	}
 94→
 95→	data, err := os.ReadFile(outPath)
 96→	if err != nil {
 97→		t.Fatalf("failed to read output: %v", err)
 98→	}
 99→	got := string(data)
100→
101→	// Verify phony all target
102→	if !strings.Contains(got, ".PHONY: all") {
103→		t.Error("missing .PHONY: all")
104→	}
105→	if !strings.Contains(got, "all: .kiln/done/build-widget.done") {
106→		t.Error("all target missing build-widget.done dependency")
107→	}
108→
109→	// Verify task target
110→	if !strings.Contains(got, ".kiln/done/build-widget.done:") {
111→		t.Error("missing build-widget target")
112→	}
113→	if !strings.Contains(got, "$(KILN) exec --task-id build-widget --prompt-file .kiln/prompts/tasks/build-widget.md && touch $@") {
114→		t.Error("missing or incorrect recipe for build-widget")
115→	}
116→}
