118→func TestRunGenMake_WithDependencies(t *testing.T) {
119→	tmp := t.TempDir()
120→	tasksPath := filepath.Join(tmp, "tasks.yaml")
121→	outPath := filepath.Join(tmp, "targets.mk")
122→
123→	yaml := `- id: alpha
124→  prompt: prompts/alpha.md
125→  needs: []
126→
127→- id: beta
128→  prompt: prompts/beta.md
129→  needs:
130→    - alpha
131→
132→- id: gamma
133→  prompt: prompts/gamma.md
134→  needs:
135→    - alpha
136→    - beta
137→`
138→	os.WriteFile(tasksPath, []byte(yaml), 0o644)
139→
140→	err := runGenMake([]string{"--tasks", tasksPath, "--out", outPath})
141→	if err != nil {
142→		t.Fatalf("unexpected error: %v", err)
143→	}
144→
145→	data, err := os.ReadFile(outPath)
146→	if err != nil {
147→		t.Fatalf("failed to read output: %v", err)
148→	}
149→	got := string(data)
150→
151→	// all target should list all three in definition order
152→	if !strings.Contains(got, "all: .kiln/done/alpha.done .kiln/done/beta.done .kiln/done/gamma.done") {
153→		t.Errorf("all target incorrect, got:\n%s", got)
154→	}
155→
156→	// alpha has no deps
157→	if !strings.Contains(got, ".kiln/done/alpha.done:\n") {
158→		t.Error("alpha should have no prerequisites")
159→	}
160→
161→	// beta depends on alpha
162→	if !strings.Contains(got, ".kiln/done/beta.done: .kiln/done/alpha.done\n") {
163→		t.Error("beta should depend on alpha")
164→	}
165→
166→	// gamma depends on alpha and beta
167→	if !strings.Contains(got, ".kiln/done/gamma.done: .kiln/done/alpha.done .kiln/done/beta.done\n") {
168→		t.Error("gamma should depend on alpha and beta")
169→	}
170→}
