172→func TestRunGenMake_DeterministicOutput(t *testing.T) {
173→	tmp := t.TempDir()
174→	tasksPath := filepath.Join(tmp, "tasks.yaml")
175→
176→	yaml := `- id: zulu
177→  prompt: z.md
178→  needs: []
179→
180→- id: alpha
181→  prompt: a.md
182→  needs: []
183→
184→- id: mike
185→  prompt: m.md
186→  needs:
187→    - zulu
188→`
189→	os.WriteFile(tasksPath, []byte(yaml), 0o644)
190→
191→	// Run twice and compare output
192→	out1 := filepath.Join(tmp, "out1.mk")
193→	out2 := filepath.Join(tmp, "out2.mk")
194→
195→	if err := runGenMake([]string{"--tasks", tasksPath, "--out", out1}); err != nil {
196→		t.Fatalf("run 1 failed: %v", err)
197→	}
198→	if err := runGenMake([]string{"--tasks", tasksPath, "--out", out2}); err != nil {
199→		t.Fatalf("run 2 failed: %v", err)
200→	}
201→
202→	d1, _ := os.ReadFile(out1)
203→	d2, _ := os.ReadFile(out2)
204→	if string(d1) != string(d2) {
205→		t.Errorf("non-deterministic output:\nrun1:\n%s\nrun2:\n%s", d1, d2)
206→	}
207→
208→	// Verify definition order preserved (zulu before alpha before mike)
209→	got := string(d1)
210→	zIdx := strings.Index(got, ".kiln/done/zulu.done:")
211→	aIdx := strings.Index(got, ".kiln/done/alpha.done:")
212→	mIdx := strings.Index(got, ".kiln/done/mike.done:")
213→	if zIdx >= aIdx || aIdx >= mIdx {
214→		t.Errorf("targets not in definition order: z=%d a=%d m=%d", zIdx, aIdx, mIdx)
215→	}
216→}
