293→// fakeCommandBuilder returns a commandBuilder that runs a helper process
294→// instead of the real claude binary. The helper process behaviour is
295→// controlled by the env var KILN_TEST_HELPER_MODE.
296→func fakeCommandBuilder(mode string) func(string) *exec.Cmd {
297→	return func(prompt string) *exec.Cmd {
298→		cmd := exec.Command(os.Args[0], "-test.run=TestHelperProcess", "--", prompt)
299→		cmd.Env = append(os.Environ(), "KILN_TEST_HELPER_MODE="+mode)
300→		return cmd
301→	}
302→}
303→
304→// TestHelperProcess is invoked as a subprocess by the fake command builder.
305→// It is not a real test — the guard at the top prevents it from running
306→// as part of the normal test suite.
307→func TestHelperProcess(t *testing.T) {
308→	mode := os.Getenv("KILN_TEST_HELPER_MODE")
309→	if mode == "" {
310→		return // not invoked as a helper
311→	}
312→
313→	switch mode {
314→	case "success":
315→		// Echo the prompt back as fake stream-json output
316→		args := os.Args
317→		for i, a := range args {
318→			if a == "--" {
319→				if i+1 < len(args) {
320→					os.Stdout.WriteString(`{"type":"assistant","content":"` + args[i+1] + `"}` + "\n")
321→				}
322→				break
323→			}
324→		}
